parameters.jsCode:
const response = $json;

// prova a trovare il testo nella risposta OpenAI
let text = null;

if (response.output && Array.isArray(response.output)) {
  for (const item of response.output) {
    if (item.content && Array.isArray(item.content)) {
      for (const content of item.content) {
        if (content.type === 'output_text' && content.text) {
          text = content.text;
          break;
        }
      }
    }
    if (text) break;
  }
}

if (!text) {
  throw new Error('Could not find output_text in OpenAI response');
}

// pulizia base
text = text.trim();

// parse JSON
let parsed;
try {
  parsed = JSON.parse(text);
} catch (err) {
  throw new Error(`Failed to parse model JSON: ${err.message}\nRaw text:\n${text}`);
}

// week_id dal flusso precedente
const weekId = $('Set week_id').first().json.week_id;

return [
  {
    json: {
      week_id: weekId,
      theme: parsed.week_theme,
      trend_summary: parsed.trend_fit_summary,
      asset_request_message: parsed.asset_request_message,
      status: 'waiting_assets',
      content_plan_json: JSON.stringify(parsed.content_plan)
    }
  }
];

