const targetWeekId = $('Set week_id').first().json.week_id;
const items = $input.all();

const match = items
  .map(item => item.json)
  .find(row => row.week_id === targetWeekId);

if (!match) {
  throw new Error(`No trend_text found for week_id=${targetWeekId}`);
}

return [
  {
    json: {
      week_id: targetWeekId,
      trend_text: match.trend_text || '',
      source_query: match.source_query || '',
      raw_summary: match.raw_summary || ''
    }
  }
];

const brand = $('Get brand profile').first().json;
const trend = $('Filter trend_input').first().json;

const prompt = `
You are a senior social media strategist specialized in underground electronic music DJs.

Your task is to generate a weekly content strategy based on:
1) the artist identity
2) current trend signals

ARTIST PROFILE:
Artist name: ${brand.artist_name || ''}
Tone: ${brand.tone || ''}
Colors: ${brand.colors || ''}
Audience: ${brand.audience || ''}
Goals: ${brand.goals || ''}
Anti-patterns: ${brand.anti_patterns || ''}

INPUT TRENDS:
${trend.trend_text || ''}

CONSTRAINTS:
- Exactly 3 posts
- English only
- Content must feel underground, elegant, emotional
- No generic ideas
- No meme-based formats
- No content that feels commercial or influencer-like
- Focus on authenticity and identity

OUTPUT FORMAT (STRICT JSON ONLY):
{
  "week_theme": "string",
  "trend_fit_summary": "string",
  "content_plan": [
    {
      "post_number": 1,
      "content_type": "raw_club_energy | dj_pov | artistic_identity",
      "goal": "string",
      "required_assets": ["string", "string"]
    },
    {
      "post_number": 2,
      "content_type": "string",
      "goal": "string",
      "required_assets": ["string", "string"]
    },
    {
      "post_number": 3,
      "content_type": "string",
      "goal": "string",
      "required_assets": ["string", "string"]
    }
  ],
  "asset_request_message": "string"
}

IMPORTANT:
- Return ONLY valid JSON
- Do not add explanations
- Do not include markdown
- Do not include comments
`;

return [
  {
    json: {
      week_id: trend.week_id,
      prompt
    }
  }
];
